// Package azure is the hand-authored auth + SDK-client foundation for the
// Azure Functions Admin CLI. Azure Resource Manager requires an Azure AD
// bearer token, which the generated HTTP client's static-token model cannot
// produce; this package uses azidentity.DefaultAzureCredential (the same
// credential chain the official tooling uses) so the CLI authenticates from
// AZURE_* service-principal env vars or an existing `az login` session.
//
// This is a durable hand-authored package (no "Generated by CLI Printing
// Press" header); it is preserved across `generate --force` regen.
package azure

import (
	"context"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/Azure/azure-sdk-for-go/sdk/azcore"
	"github.com/Azure/azure-sdk-for-go/sdk/azcore/policy"
	"github.com/Azure/azure-sdk-for-go/sdk/azidentity"
	"github.com/Azure/azure-sdk-for-go/sdk/monitor/azquery"
	"github.com/Azure/azure-sdk-for-go/sdk/resourcemanager/applicationinsights/armapplicationinsights"
	"github.com/Azure/azure-sdk-for-go/sdk/resourcemanager/appservice/armappservice/v6"
	"github.com/Azure/azure-sdk-for-go/sdk/resourcemanager/resources/armsubscriptions"
)

// ARMScope is the OAuth2 scope for Azure Resource Manager access tokens.
const ARMScope = "https://management.azure.com/.default"

// PreacquiredARMTokenEnv, when set, supplies a ready-made ARM bearer token
// (e.g. from `az account get-access-token --resource https://management.azure.com
// --query accessToken -o tsv`). The CLI then uses it directly for every ARM
// client and raw ARM HTTP call, skipping DefaultAzureCredential. This is
// concurrency-safe — many command processes share one token instead of each
// shelling out to `az`, which contends on the Azure CLI token cache — and is
// handy in CI. Note: it is ARM-scoped, so the Application Insights analytics
// commands (coldstart/scaling/failures/stale) still need DefaultAzureCredential
// for their Log Analytics queries; leave this unset to use them.
const PreacquiredARMTokenEnv = "AZURE_FUNCTIONS_ADMIN_ARM_TOKEN"

var (
	credOnce sync.Once
	credVal  azcore.TokenCredential
	credErr  error
)

// staticTokenCredential implements azcore.TokenCredential by returning a fixed,
// pre-acquired bearer token regardless of the requested scope. Used only when
// PreacquiredARMTokenEnv is set (see Credential).
type staticTokenCredential struct{ token string }

func (s staticTokenCredential) GetToken(context.Context, policy.TokenRequestOptions) (azcore.AccessToken, error) {
	expiry := jwtExpiry(s.token)
	if expiry.IsZero() {
		// Token isn't a decodable JWT (or has no exp); fall back to a
		// conservative window so the SDK refreshes/reports sensibly rather
		// than trusting a possibly-stale token for too long.
		expiry = time.Now().Add(40 * time.Minute)
	}
	return azcore.AccessToken{Token: s.token, ExpiresOn: expiry}, nil
}

// jwtExpiry decodes the `exp` claim from a JWT access token's payload and
// returns it as a time. Returns the zero time if the token is not a parseable
// three-part JWT or carries no exp, so the caller can apply its own fallback.
func jwtExpiry(token string) time.Time {
	parts := strings.Split(token, ".")
	if len(parts) != 3 {
		return time.Time{}
	}
	payload, err := base64.RawURLEncoding.DecodeString(parts[1])
	if err != nil {
		return time.Time{}
	}
	var claims struct {
		Exp int64 `json:"exp"`
	}
	if err := json.Unmarshal(payload, &claims); err != nil || claims.Exp == 0 {
		return time.Time{}
	}
	return time.Unix(claims.Exp, 0)
}

// Credential returns a process-wide token credential. If PreacquiredARMTokenEnv
// is set it returns a static credential wrapping that token; otherwise it
// returns azidentity.DefaultAzureCredential, whose default chain resolves, in
// order: environment service principal (AZURE_TENANT_ID/AZURE_CLIENT_ID/
// AZURE_CLIENT_SECRET), workload/managed identity, then an `az login` session —
// so both CI service principals and a developer's local login work with no
// CLI-specific configuration.
func Credential() (azcore.TokenCredential, error) {
	credOnce.Do(func() {
		if tok := os.Getenv(PreacquiredARMTokenEnv); tok != "" {
			credVal = staticTokenCredential{token: tok}
			return
		}
		credVal, credErr = azidentity.NewDefaultAzureCredential(nil)
	})
	if credErr != nil {
		return nil, fmt.Errorf("azure credential: %w (set AZURE_TENANT_ID, AZURE_CLIENT_ID, AZURE_CLIENT_SECRET or run `az login`)", credErr)
	}
	return credVal, nil
}

// SubscriptionID resolves the active subscription. An explicit value (e.g. a
// command flag) wins; otherwise AZURE_SUBSCRIPTION_ID is used. Returns an
// actionable error when neither is set so commands can fail with guidance
// instead of an opaque SDK error.
func SubscriptionID(explicit string) (string, error) {
	if explicit != "" {
		return explicit, nil
	}
	if v := os.Getenv("AZURE_SUBSCRIPTION_ID"); v != "" {
		return v, nil
	}
	return "", fmt.Errorf("no subscription: pass --subscription or set AZURE_SUBSCRIPTION_ID")
}

// AppServiceFactory builds the armappservice client factory for a subscription.
// WebAppsClient (factory.NewWebAppsClient()) covers function apps, functions,
// app settings, host/function keys, and slots; PlansClient covers serverfarms.
func AppServiceFactory(subscriptionID string) (*armappservice.ClientFactory, error) {
	cred, err := Credential()
	if err != nil {
		return nil, err
	}
	return armappservice.NewClientFactory(subscriptionID, cred, nil)
}

// SubscriptionsClient lists subscriptions reachable by the credential.
func SubscriptionsClient() (*armsubscriptions.Client, error) {
	cred, err := Credential()
	if err != nil {
		return nil, err
	}
	return armsubscriptions.NewClient(cred, nil)
}

// LogsClient queries Application Insights / Log Analytics with KQL, used to
// derive cold-start, scaling, and failure analytics that ARM does not expose.
func LogsClient() (*azquery.LogsClient, error) {
	cred, err := Credential()
	if err != nil {
		return nil, err
	}
	return azquery.NewLogsClient(cred, nil)
}

// AppInsightsComponentsClient lists Application Insights components, used to
// resolve a Function App's AI resource ID (by matching instrumentation key)
// so its telemetry can be queried with KQL.
func AppInsightsComponentsClient(subscriptionID string) (*armapplicationinsights.ComponentsClient, error) {
	cred, err := Credential()
	if err != nil {
		return nil, err
	}
	return armapplicationinsights.NewComponentsClient(subscriptionID, cred, nil)
}

// ARMBearer returns an "Authorization: Bearer <token>" value for raw ARM HTTP
// calls (e.g. the listkeys POST actions) made through the generated client via
// GetWithHeaders/PostWithHeaders. The SDK clients above manage their own tokens.
func ARMBearer(ctx context.Context) (string, error) {
	if tok := os.Getenv(PreacquiredARMTokenEnv); tok != "" {
		return "Bearer " + tok, nil
	}
	cred, err := Credential()
	if err != nil {
		return "", err
	}
	tok, err := cred.GetToken(ctx, policy.TokenRequestOptions{Scopes: []string{ARMScope}})
	if err != nil {
		return "", fmt.Errorf("acquiring ARM token: %w", err)
	}
	return "Bearer " + tok.Token, nil
}
